        svd.fit(features)
        s = svd.singular_values_

    if self.mode!=0:
        s = s[np.abs(self.mode)-1:]
    s_norm  = s/np.sum(s)
    uniform = np.ones(len(s))/(len(s))

    if self.mode<0:
        kl = entropy(s_norm, uniform)
    if self.mode>0:
        kl = entropy(uniform, s_norm)
    if self.mode==0:
        kl = s_norm

    return kl

